export const getRandomQuestions = (classGroup, subject, count = 5) => {
  const allQuestions = questionBank[classGroup]?.[subject] || []
  const shuffled = [...allQuestions].sort(() => Math.random() - 0.5)
  return shuffled.slice(0, count)
}
  